/**
 * Heavenly Nature Ministry - Enhanced Main JavaScript
 * Final production version with improved UI interactions and performance
 */

(function() {
  'use strict';
  
  // Initialize when DOM is fully loaded
  document.addEventListener('DOMContentLoaded', function() {
    
    // ======================
    // Utility Functions
    // ======================
    
    /**
     * Throttles a function to limit how often it can be called
     * @param {Function} callback The function to throttle
     * @param {number} delay The delay in milliseconds
     * @returns {Function} The throttled function
     */
    function throttle(callback, delay = 200) {
      let throttleTimeout = null;
      let storedEvent = null;

      const throttledEventHandler = event => {
        storedEvent = event;
        if (throttleTimeout) return;

        throttleTimeout = setTimeout(() => {
          callback(storedEvent);
          throttleTimeout = null;
        }, delay);
      };

      return throttledEventHandler;
    }
    
    /**
     * Debounces a function to delay execution until after wait milliseconds
     * @param {Function} func The function to debounce
     * @param {number} wait The number of milliseconds to delay
     * @returns {Function} The debounced function
     */
    function debounce(func, wait) {
      let timeout;
      return function executedFunction(...args) {
        const later = () => {
          clearTimeout(timeout);
          func(...args);
        };
        clearTimeout(timeout);
        timeout = setTimeout(later, wait);
      };
    }
    
    // ======================
    // Mobile Menu Functionality
    // ======================
    const menuToggle = document.querySelector('.menu-toggle');
    const mobileMenu = document.getElementById('mobile-menu');
    const mobileLinks = document.querySelectorAll('.mobile-nav-link');
    
    function toggleMobileMenu() {
      const isExpanded = menuToggle.classList.toggle('is-active');
      mobileMenu.classList.toggle('active');
      document.body.classList.toggle('no-scroll', isExpanded);
      menuToggle.setAttribute('aria-expanded', isExpanded);
      
      // Add animation to menu items when opening
      if (isExpanded) {
        const menuItems = mobileMenu.querySelectorAll('li');
        menuItems.forEach((item, index) => {
          item.style.animationDelay = `${index * 0.1}s`;
          item.classList.add('fade-in-up');
        });
      }
    }

    function closeMobileMenu() {
      menuToggle.classList.remove('is-active');
      mobileMenu.classList.remove('active');
      document.body.classList.remove('no-scroll');
      menuToggle.setAttribute('aria-expanded', 'false');
      
      // Remove animations
      const menuItems = mobileMenu.querySelectorAll('li');
      menuItems.forEach(item => {
        item.classList.remove('fade-in-up');
        item.style.animationDelay = '';
      });
    }

    if (menuToggle && mobileMenu) {
      menuToggle.setAttribute('aria-expanded', 'false');
      menuToggle.setAttribute('aria-controls', 'mobile-menu');
      menuToggle.setAttribute('aria-label', 'Toggle menu');
      
      menuToggle.addEventListener('click', function(e) {
        e.stopPropagation();
        toggleMobileMenu();
      });
      
      mobileLinks.forEach(link => {
        link.addEventListener('click', closeMobileMenu);
      });

      document.addEventListener('click', function(e) {
        if (mobileMenu.classList.contains('active') && 
            !menuToggle.contains(e.target) && 
            !mobileMenu.contains(e.target)) {
          closeMobileMenu();
        }
      });

      document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && mobileMenu.classList.contains('active')) {
          closeMobileMenu();
        }
      });
    }

    // ======================
    // Header Scroll Effect
    // ======================
    const header = document.querySelector('.site-header');
    
    function updateHeaderOnScroll() {
      if (window.scrollY > 50) {
        header.classList.add('scrolled');
      } else {
        header.classList.remove('scrolled');
      }
    }
    
    window.addEventListener('scroll', throttle(updateHeaderOnScroll, 10));
    updateHeaderOnScroll(); // Initialize on load

    // ======================
    // Animation on Scroll (AOS)
    // ======================
    if (typeof AOS !== 'undefined') {
      AOS.init({
        duration: 800,
        easing: 'ease-in-out',
        once: true,
        offset: 50,
        disable: function() {
          return window.innerWidth < 768;
        }
      });
    } else {
      // Fallback if AOS doesn't load
      const animatedElements = document.querySelectorAll('[data-aos]');
      animatedElements.forEach(el => {
        el.style.opacity = '1';
        el.style.transform = 'translateY(0)';
      });
    }

    // ======================
    // Back to Top Button
    // ======================
    const backToTopButton = document.getElementById('back-to-top');
    if (backToTopButton) {
      function toggleBackToTop() {
        const isVisible = window.scrollY > 300;
        backToTopButton.classList.toggle('show', isVisible);
        backToTopButton.setAttribute('aria-hidden', !isVisible);
      }

      backToTopButton.setAttribute('aria-label', 'Back to top');
      backToTopButton.setAttribute('aria-hidden', 'true');

      window.addEventListener('scroll', throttle(toggleBackToTop, 10));
      toggleBackToTop(); // Check on initial load

      backToTopButton.addEventListener('click', function(e) {
        e.preventDefault();
        window.scrollTo({
          top: 0,
          behavior: 'smooth'
        });
        // Move focus to the top of the page for accessibility
        const header = document.querySelector('header');
        if (header) {
          header.setAttribute('tabindex', '-1');
          header.focus();
        }
      });
    }

    // ======================
    // Smooth Scrolling
    // ======================
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
      anchor.addEventListener('click', function(e) {
        const targetId = this.getAttribute('href');
        
        if (targetId === '#' || targetId === '#!' || targetId.startsWith('javascript:')) {
          return;
        }

        const targetElement = document.querySelector(targetId);
        if (targetElement) {
          e.preventDefault();
          
          const headerHeight = document.querySelector('.site-header')?.offsetHeight || 85;
          const targetPosition = targetElement.getBoundingClientRect().top + window.pageYOffset - headerHeight;

          window.scrollTo({
            top: targetPosition,
            behavior: 'smooth'
          });

          if (history.pushState) {
            history.pushState(null, null, targetId);
          } else {
            location.hash = targetId;
          }

          targetElement.setAttribute('tabindex', '-1');
          targetElement.focus();
        }
      });
    });

    // ======================
    // Current Year in Footer
    // ======================
    const yearElement = document.getElementById('current-year');
    if (yearElement) {
      yearElement.textContent = new Date().getFullYear();
    }

    // ======================
    // Donation Button Placeholder
    // ======================
    const donationButtons = document.querySelectorAll('#donate .cta-button');
    donationButtons.forEach(button => {
      button.addEventListener('click', function(e) {
        e.preventDefault();
        // Create a beautiful modal instead of alert
        showNotification('Thank you for your interest in supporting our ministry! Our online donation system is currently being set up. Please check back soon or contact us directly for donation options.', 'info');
      });
    });

    // ======================
    // Copy to Clipboard Functionality
    // ======================
    document.querySelectorAll('.copy-button').forEach(button => {
      button.addEventListener('click', function() {
        const textToCopy = this.getAttribute('data-clipboard-text');
        if (!textToCopy) return;

        navigator.clipboard.writeText(textToCopy).then(() => {
          const originalText = this.innerHTML;
          this.innerHTML = '<i class="fas fa-check"></i> Copied!';
          this.disabled = true;
          
          // Show success notification
          showNotification('Account number copied to clipboard!', 'success');
          
          setTimeout(() => {
            this.innerHTML = originalText;
            this.disabled = false;
          }, 2000);
        }).catch(err => {
          console.error('Failed to copy text: ', err);
          showNotification('Failed to copy. Please try again or copy manually.', 'error');
        });
      });
    });

    // ======================
    // Form Validation & Submission
    // ======================
    const contactForm = document.querySelector('.contact-form');
    if (contactForm) {
      contactForm.addEventListener('submit', function(e) {
        e.preventDefault();
        
        // Simple validation
        let isValid = true;
        const requiredFields = contactForm.querySelectorAll('[required]');
        
        requiredFields.forEach(field => {
          if (!field.value.trim()) {
            field.classList.add('error');
            isValid = false;
            
            // Add error message if not exists
            if (!field.nextElementSibling || !field.nextElementSibling.classList.contains('error-message')) {
              const errorMsg = document.createElement('div');
              errorMsg.className = 'error-message';
              errorMsg.textContent = 'This field is required';
              field.parentNode.insertBefore(errorMsg, field.nextSibling);
            }
          } else {
            field.classList.remove('error');
            const errorMsg = field.nextElementSibling;
            if (errorMsg && errorMsg.classList.contains('error-message')) {
              errorMsg.remove();
            }
          }
        });
        
        if (isValid) {
          // Show loading state
          const submitButton = contactForm.querySelector('.submit-button');
          const originalText = submitButton.innerHTML;
          submitButton.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Sending...';
          submitButton.disabled = true;
          
          // Simulate form submission (replace with actual form submission)
          setTimeout(() => {
            showNotification('Your message has been sent successfully! We will get back to you soon.', 'success');
            contactForm.reset();
            submitButton.innerHTML = originalText;
            submitButton.disabled = false;
          }, 1500);
        }
      });
      
      // Remove error state on input
      const formInputs = contactForm.querySelectorAll('input, textarea');
      formInputs.forEach(input => {
        input.addEventListener('input', function() {
          if (this.value.trim()) {
            this.classList.remove('error');
            const errorMsg = this.nextElementSibling;
            if (errorMsg && errorMsg.classList.contains('error-message')) {
              errorMsg.remove();
            }
          }
        });
      });
    }

    // ======================
    // Lazy Loading for Images
    // ======================
    function lazyLoadImages() {
      const lazyImages = document.querySelectorAll('img[loading="lazy"]');
      
      if ('loading' in HTMLImageElement.prototype) {
        // Native lazy loading supported
        lazyImages.forEach(img => {
          if (img.dataset.src) {
            img.src = img.dataset.src;
          }
          img.classList.add('loaded');
        });
      } else if (typeof LazyLoad !== 'undefined') {
        // Fallback for browsers without native lazy loading
        const lazyLoadInstance = new LazyLoad({
          elements_selector: '[loading="lazy"]',
          threshold: 100,
          callback_loaded: (img) => {
            img.classList.add('loaded');
          }
        });
      } else {
        // Fallback if no lazy loading support
        lazyImages.forEach(img => {
          if (img.dataset.src) {
            img.src = img.dataset.src;
          }
          img.classList.add('loaded');
        });
      }
    }
    
    lazyLoadImages();

    // ======================
    // Notification System
    // ======================
    function showNotification(message, type = 'info') {
      // Create notification element
      const notification = document.createElement('div');
      notification.className = `notification notification-${type}`;
      notification.setAttribute('role', 'alert');
      notification.setAttribute('aria-live', 'assertive');
      
      // Add icon based on type
      let icon = 'info-circle';
      if (type === 'success') icon = 'check-circle';
      if (type === 'error') icon = 'exclamation-circle';
      
      notification.innerHTML = `
        <i class="fas fa-${icon}"></i>
        <span>${message}</span>
        <button class="notification-close" aria-label="Close notification">
          <i class="fas fa-times"></i>
        </button>
      `;
      
      // Add to page
      document.body.appendChild(notification);
      
      // Animate in
      setTimeout(() => {
        notification.classList.add('show');
      }, 10);
      
      // Set timeout to remove
      setTimeout(() => {
        hideNotification(notification);
      }, 5000);
      
      // Close on button click
      const closeBtn = notification.querySelector('.notification-close');
      closeBtn.addEventListener('click', () => {
        hideNotification(notification);
      });
    }
    
    function hideNotification(notification) {
      notification.classList.remove('show');
      setTimeout(() => {
        if (notification.parentNode) {
          notification.parentNode.removeChild(notification);
        }
      }, 300);
    }

    // ======================
    // Interactive Elements Enhancement
    // ======================
    
    // Add hover effects to cards
    const cards = document.querySelectorAll('.mission-card, .donation-card, .info-card');
    cards.forEach(card => {
      card.addEventListener('mouseenter', function() {
        this.style.transition = 'transform 0.3s ease, box-shadow 0.3s ease';
      });
    });
    
    // Add animation to gallery items
    const galleryItems = document.querySelectorAll('.gallery-item');
    galleryItems.forEach(item => {
      item.addEventListener('mouseenter', function() {
        const caption = this.querySelector('.gallery-caption');
        if (caption) {
          caption.style.transform = 'translateY(0)';
        }
      });
      
      item.addEventListener('mouseleave', function() {
        const caption = this.querySelector('.gallery-caption');
        if (caption) {
          caption.style.transform = 'translateY(100%)';
        }
      });
    });
    
    // Add loading animation to buttons
    const buttons = document.querySelectorAll('button, .cta-button');
    buttons.forEach(button => {
      button.addEventListener('click', function(e) {
        // Add ripple effect
        const ripple = document.createElement('span');
        ripple.classList.add('ripple-effect');
        this.appendChild(ripple);
        
        const rect = this.getBoundingClientRect();
        const size = Math.max(rect.width, rect.height);
        const x = e.clientX - rect.left - size / 2;
        const y = e.clientY - rect.top - size / 2;
        
        ripple.style.width = ripple.style.height = `${size}px`;
        ripple.style.left = `${x}px`;
        ripple.style.top = `${y}px`;
        
        setTimeout(() => {
          if (ripple.parentNode === this) {
            this.removeChild(ripple);
          }
        }, 600);
      });
    });

    // ======================
    // Performance Optimization
    // ======================
    
    // Preload critical images
    function preloadCriticalImages() {
      const criticalImages = document.querySelectorAll('img[loading="eager"]');
      criticalImages.forEach(img => {
        if (img.dataset.src) {
          img.src = img.dataset.src;
        }
      });
    }
    
    // Initialize everything
    function init() {
      preloadCriticalImages();
      updateHeaderOnScroll();
      toggleBackToTop();
      
      // Add loaded class to body when everything is ready
      setTimeout(() => {
        document.body.classList.add('loaded');
      }, 100);
    }
    
    init();
  });

  // CSS for notifications and ripple effects (injected via JS)
  const style = document.createElement('style');
  style.textContent = `
    .notification {
      position: fixed;
      top: 100px;
      right: 20px;
      background: white;
      color: #333;
      padding: 1rem 1.5rem;
      border-radius: 8px;
      box-shadow: 0 4px 15px rgba(0,0,0,0.15);
      display: flex;
      align-items: center;
      gap: 0.75rem;
      z-index: 9999;
      transform: translateX(100%);
      transition: transform 0.3s ease;
      max-width: 350px;
    }
    
    .notification.show {
      transform: translateX(0);
    }
    
    .notification-success {
      border-left: 4px solid #4caf50;
    }
    
    .notification-error {
      border-left: 4px solid #f44336;
    }
    
    .notification-info {
      border-left: 4px solid #2196f3;
    }
    
    .notification-close {
      background: none;
      border: none;
      cursor: pointer;
      margin-left: auto;
      color: #666;
    }
    
    .ripple-effect {
      position: absolute;
      border-radius: 50%;
      background-color: rgba(255, 255, 255, 0.4);
      transform: scale(0);
      animation: ripple 0.6s linear;
    }
    
    @keyframes ripple {
      to {
        transform: scale(4);
        opacity: 0;
      }
    }
    
    .fade-in-up {
      animation: fadeInUp 0.5s ease forwards;
      opacity: 0;
    }
    
    @keyframes fadeInUp {
      from {
        opacity: 0;
        transform: translateY(20px);
      }
      to {
        opacity: 1;
        transform: translateY(0);
      }
    }
    
    .loaded .hero-content {
      animation: fadeInUp 1s ease;
    }
  `;
  document.head.appendChild(style);

})();